#include <stdio.h> 
int main()
{
	int h,w,k;

	scanf("%d %d %d",&w,&h,&k) ;


	int sum = 0 ; 

	while(k)
	{

		if (h == 1 && w == 1)
		    sum = sum + 1;
		if (h == 1 && w != 1)
		    sum = sum + w;
		if (h != 1 && w == 1)
		    sum = sum + h;
		if (h != 1 && w != 1)
		    sum = sum + (w*2 + h*2 - 4) ;

		h = h - 4 ;
		w = w - 4 ;


		k--;

	}
	printf("%d",sum);

	return 0;
}

