use std::io;

macro_rules! readln {
    () => {{
        use std::io;
        let mut buf = String::new();
        io::stdin().read_line(&mut buf).unwrap();
        buf.trim().to_string()
    }};
    ( $t:ty ) => {{
        let input = readln!();
        input.parse::<$t>().unwrap()
    }};
    ( $( $t:ty ),+ ) => {{
        let input = readln!();
        let mut input = input.split_whitespace();
        (
            $(
                input.next().unwrap().parse::<$t>().unwrap(),
            )+
        )
    }}
}

fn main() {
    let (width, height, count) = readln!(i32, i32, i32);

    let mut result = 0;
    for i in 0..count {
        let curr_width = width - 4 * i;
        let curr_height = height - 4 * i;

        result += 2 * (curr_width + curr_height - 2);
    }

    println!("{}", result);
}
